"use client";

import { motion, Variants } from "framer-motion";
import { useState } from "react";
import SmoothScroll from "@/components/smoothScroll";
import {
  DesignCard,
  CategoryTabs,
  DesignHero,
  DesignQuote,
  designKnowledge,
  DesignItem
} from "@/components/design";

const containerVariants: Variants = {
  hidden: { opacity: 0 },
  visible: {
    opacity: 1,
    transition: {
      staggerChildren: 0.1
    }
  }
};

const itemVariants: Variants = {
  hidden: { y: 50, opacity: 0 },
  visible: {
    y: 0,
    opacity: 1,
    transition: {
      stiffness: 100,
      damping: 12
    }
  }
};

const cardVariants: Variants = {
  hidden: { scale: 0.8, opacity: 0, rotateY: -15 },
  visible: {
    scale: 1,
    opacity: 1,
    rotateY: 0,
    transition: {
      stiffness: 100,
      damping: 15
    }
  }
};

export default function DesignPage() {
  const [selectedItem, setSelectedItem] = useState<DesignItem | null>(null);
  const [activeCategory, setActiveCategory] = useState<number>(0);

  return (
    <SmoothScroll>
      <div className="min-h-screen bg-black text-white overflow-x-hidden">
        {/* Hero Section */}
        <DesignHero />

        {/* Category Tabs */}
        <CategoryTabs
          categories={designKnowledge}
          activeCategory={activeCategory}
          onCategoryChange={setActiveCategory}
        />

        {/* Content Section */}
        <motion.section
          className="max-w-6xl mx-auto px-6 py-16"
          key={activeCategory}
          variants={containerVariants}
          initial="hidden"
          animate="visible"
        >
          <motion.h2
            className="text-3xl font-bold mb-12 text-center"
            variants={itemVariants}
            style={{ color: designKnowledge[activeCategory].color }}
          >
            {designKnowledge[activeCategory].category}
          </motion.h2>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
            {designKnowledge[activeCategory].items.map((item) => (
              <DesignCard
                key={item.name}
                item={item}
                color={designKnowledge[activeCategory].color}
                isSelected={selectedItem?.name === item.name}
                onSelect={() =>
                  setSelectedItem(
                    selectedItem?.name === item.name ? null : item
                  )
                }
                variants={cardVariants}
              />
            ))}
          </div>
        </motion.section>

        {/* Bottom Quote Section */}
        <DesignQuote />

        {/* CSS Animation */}
        <style jsx>{`
            @keyframes gridMove {
                0% {
                    transform: translate(0, 0);
                }
                100% {
                    transform: translate(50px, 50px);
                }
            }
        `}</style>
      </div>
    </SmoothScroll>
  );
}
